## SDUI System Exploration Report

I've thoroughly explored the Server Driven UI (SDUI) system in your codebase. Here's a complete analysis:

### 1. ADAPTER REGISTRATION PATTERN

**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/adapters/index.ts`

The adapter pattern uses a centralized registry approach:

```typescript
const adapters: Record<string, SDUIComponentRenderer> = {
  heading: HeadingAdapter as SDUIComponentRenderer,
  text: TextAdapter as SDUIComponentRenderer,
  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
  points_input: PointsInputAdapter as SDUIComponentRenderer,
  button: ButtonAdapter as SDUIComponentRenderer,
  link: LinkAdapter as SDUIComponentRenderer,
  alert: AlertAdapter as SDUIComponentRenderer,
  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
  separator: SeparatorAdapter as SDUIComponentRenderer,
  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
  rich_text: RichTextAdapter as SDUIComponentRenderer,
  voucher_card: VoucherCardAdapter as SDUIComponentRenderer,
  empty_state: EmptyStateAdapter as SDUIComponentRenderer,
};

export function registerAllAdapters(): void {
  Object.entries(adapters).forEach(([type, renderer]) => {
    registerToDefault(type, renderer);
  });
}
```

**Key Points:**
- 14 adapters currently registered
- Each adapter is a React component matching signature: `{ props: P; context: SDUIContext }`
- Registration is immutable and mutates the default registry
- Tests verify all 14 adapters are exported and registered correctly

---

### 2. TYPE SYSTEM & MODELS

**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/models/index.ts`

Complete type hierarchy:

#### Context System
```typescript
export type SDUIContextValue = 
  | string | number | boolean | null 
  | SDUIContext | SDUIContextValue[];

export interface SDUIContext {
  [key: string]: SDUIContextValue;
}
```

#### JSON Logic Subset (for rules & conditions)
```typescript
// Variable reference with dot notation
export interface SDUIVarOperator {
  var: string; // e.g., 'form.points', 'balance.pointsFormatted'
}

// Comparison operators
export interface SDUIComparisonRule {
  '=='?: [SDUILogicOperand, SDUILogicOperand];
  '!='?: [SDUILogicOperand, SDUILogicOperand];
  '>'?: [SDUILogicOperand, SDUILogicOperand];
  '<'?: [SDUILogicOperand, SDUILogicOperand];
  '>='?: [SDUILogicOperand, SDUILogicOperand];
  '<='?: [SDUILogicOperand, SDUILogicOperand];
}

// Logical operators
export interface SDUILogicalRule {
  and?: SDUIRule[];
  or?: SDUIRule[];
  '!'?: SDUIRule;
}

export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;
```

#### Conditionals & Validation
```typescript
// Used for visibility, enabled state, etc.
export interface SDUIConditional {
  rule: SDUIRule;
}

export interface SDUIValidationRule {
  rule: SDUIRule;
  message: string;
}

export interface SDUIValidation {
  rules: SDUIValidationRule[];
}
```

#### Rich Text
```typescript
export interface SDUITextNode {
  type: 'text';
  value: string;
  bold?: boolean;
  italic?: boolean;
  color?: string;
}

export interface SDUILinkNode {
  type: 'link';
  text: string;
  to: string;
  trackEvent?: string;
}

export interface SDUIIconNode {
  type: 'icon';
  name: string;
  color?: string;
  size?: number;
}

export interface SDUILineBreakNode {
  type: 'br';
}

export type SDUIRichTextChild = 
  | SDUITextNode | SDUILinkNode | SDUIIconNode | SDUILineBreakNode;
```

#### Component & Screen Structure
```typescript
export interface SDUIComponent<T extends string = string> {
  type: T;
  props: SDUIComponentProps;
  visible?: SDUIConditional;
}

export interface SDUIScreen {
  id: string;
  context: SDUIContext;
  header?: SDUIComponent;
  body: SDUIComponent[];
  footer?: SDUIComponent;
}

export interface SDUIScreenResponse {
  screen: SDUIScreen;
}

export type SDUIComponentRenderer<P extends SDUIComponentProps = SDUIComponentProps> =
  ComponentType<{
    props: P;
    context: SDUIContext;
  }>;
```

#### Known Types
```typescript
export const SDUI_KNOWN_TYPES = [
  'heading', 'text', 'balance_display', 'points_input', 'button', 'link',
  'alert', 'list_text_icon', 'separator', 'icon_text_row', 'section_heading',
  'nav_header', 'rich_text', 'voucher_card', 'empty_state',
] as const;
```

---

### 3. REGISTRY & RESOLUTION

**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/registry/index.ts`

```typescript
// Immutable registry pattern
export function createRegistry(initial?: SDUIComponentRegistry): SDUIComponentRegistry {
  return { ...initial };
}

export function registerComponent(
  registry: SDUIComponentRegistry,
  type: string,
  renderer: SDUIComponentRenderer,
): SDUIComponentRegistry {
  return { ...registry, [type]: renderer };
}

export function getRenderer(
  registry: SDUIComponentRegistry,
  type: string,
): SDUIComponentRenderer | undefined {
  return registry[type];
}

// Default registry (mutated by registerToDefault)
const defaultRegistry: SDUIComponentRegistry = {};

export function getDefaultRegistry(): SDUIComponentRegistry {
  return defaultRegistry;
}

export function registerToDefault(
  type: string,
  renderer: SDUIComponentRenderer,
): void {
  defaultRegistry[type] = renderer;
}
```

**Design Pattern:**
- Creates immutable registry copies for testing
- Maintains a module-level `defaultRegistry` singleton
- `registerToDefault()` mutates the singleton

---

### 4. SCREEN RENDERING PIPELINE

**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/renderer/ScreenRenderer.tsx`

The rendering engine orchestrates three key processes:

#### Visibility Resolution
```typescript
function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
  if (!component.visible) return true;
  const { rule } = component.visible;
  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
    return true;
  }
  return evaluateRule(rule, context);
}
```

#### Conditional Separation
```typescript
function separateConditionals(props: SDUIComponentProps): {
  interpolatable: SDUIComponentProps;
  conditionals: Record<string, SDUIConditional>;
} {
  const interpolatable: SDUIComponentProps = {};
  const conditionals: Record<string, SDUIConditional> = {};

  for (const key of Object.keys(props)) {
    if (isConditional(props[key])) {
      conditionals[key] = props[key] as SDUIConditional;
    } else {
      interpolatable[key] = props[key];
    }
  }

  return { interpolatable, conditionals };
}
```

#### Component Rendering with Fallback
```typescript
function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
) {
  if (!isVisible(component, context)) return null;

  const { interpolatable, conditionals } = separateConditionals(component.props);
  const interpolatedProps = {
    ...interpolateDeep(interpolatable, context),
    ...conditionals, // Passed as-is for adapter evaluation
  };

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={key}
        type={component.type}
        props={interpolatedProps}
      />
    );
  }

  return <Renderer key={key} props={interpolatedProps} context={context} />;
}
```

#### Main Renderer
```typescript
export default function ScreenRenderer({
  screen,
  registry,
}: ScreenRendererProps) {
  const activeRegistry = registry ?? getDefaultRegistry();
  const { context, header, body, footer } = screen;

  return (
    <View style={{ flex: 1 }}>
      {header && renderComponent(header, context, activeRegistry, 'header')}

      <View style={{ flex: 1 }}>
        {(body ?? []).map((component, index) =>
          renderComponent(
            component,
            context,
            activeRegistry,
            `${component.type}-${index}`,
          ),
        )}
      </View>

      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
    </View>
  );
}
```

---

### 5. UTILITY ENGINES

#### String Interpolation
**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/utils/interpolation.ts`

```typescript
const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
const DENIED_KEYS = new Set(['__proto__', 'constructor', 'prototype']);

export function resolveContextPath(
  context: SDUIContext,
  path: string,
): SDUIContextValue {
  const segments = path.trim().split('.');
  let current: SDUIContextValue = context;

  for (const segment of segments) {
    if (current === null || current === undefined) return '';
    if (typeof current !== 'object') return '';
    if (DENIED_KEYS.has(segment)) return ''; // Prototype pollution protection

    if (Array.isArray(current)) {
      const index = parseInt(segment, 10);
      if (isNaN(index) || index < 0 || index >= current.length) return '';
      current = current[index] as SDUIContextValue;
    } else {
      current = (current as SDUIContext)[segment];
    }
  }

  return current ?? '';
}

export function interpolateString(
  template: string,
  context: SDUIContext,
): string {
  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
    const value = resolveContextPath(context, path);
    if (value === null || value === undefined) return '';
    if (typeof value === 'object') return '';
    return String(value);
  });
}

export function interpolateDeep<T>(value: T, context: SDUIContext): T {
  if (typeof value === 'string') {
    return interpolateString(value, context) as T;
  }
  if (Array.isArray(value)) {
    return value.map(item => interpolateDeep(item, context)) as T;
  }
  if (value !== null && typeof value === 'object') {
    const result: Record<string, unknown> = {};
    for (const key of Object.keys(value)) {
      result[key] = interpolateDeep(
        (value as Record<string, unknown>)[key],
        context,
      );
    }
    return result as T;
  }
  return value;
}
```

**Security Features:**
- Prototype pollution protection via `DENIED_KEYS`
- Bounds checking for array indexing
- Type coercion guards

#### JSON Logic Evaluator
**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/utils/jsonLogic.ts`

```typescript
const MAX_DEPTH = 20; // Prevent infinite recursion
const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);

function evaluateComparison(
  operator: string,
  operands: [SDUILogicOperand, SDUILogicOperand],
  context: SDUIContext,
  depth: number,
): boolean {
  const left = resolveOperand(operands[0], context, depth);
  const right = resolveOperand(operands[1], context, depth);

  switch (operator) {
    case '==': return left == right;  // Loose equality
    case '!=': return left != right;
    case '>': 
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left > right;
    case '<': 
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left < right;
    case '>=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left >= right;
    case '<=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left <= right;
    default: return false;
  }
}

function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
  if (!rule || typeof rule !== 'object') return false;
  if (depth > MAX_DEPTH) return false;

  const keys = Object.keys(rule);
  if (keys.length === 0) return false;

  const operator = keys[0];
  const operands = (rule as Record<string, unknown>)[operator];

  // Logical operators: and, or, !
  if (operator === 'and') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === 'or') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === '!') {
    const inner = Array.isArray(operands) ? operands[0] : operands;
    return !evaluate(inner as SDUIRule, context, depth + 1);
  }

  // Comparison operators
  if (COMPARISON_OPS.has(operator)) {
    if (!Array.isArray(operands) || operands.length !== 2) return false;
    return evaluateComparison(
      operator,
      operands as [SDUILogicOperand, SDUILogicOperand],
      context,
      depth,
    );
  }

  return false;
}

export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
  return evaluate(rule, context, 0);
}
```

**Features:**
- Recursive evaluation with MAX_DEPTH guard
- Support for comparison (`==`, `!=`, `>`, `<`, `>=`, `<=`)
- Support for logical operators (`and`, `or`, `!`)
- Type-safe comparisons for numeric operators
- Loose equality for `==`/`!=`

