### 4. SCREEN RENDERING PIPELINE

**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/renderer/ScreenRenderer.tsx`

The rendering engine orchestrates three key processes:

#### Visibility Resolution
```typescript
function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
  if (!component.visible) return true;
  const { rule } = component.visible;
  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
    return true;
  }
  return evaluateRule(rule, context);
}
```

#### Conditional Separation
```typescript
function separateConditionals(props: SDUIComponentProps): {
  interpolatable: SDUIComponentProps;
  conditionals: Record<string, SDUIConditional>;
} {
  const interpolatable: SDUIComponentProps = {};
  const conditionals: Record<string, SDUIConditional> = {};

  for (const key of Object.keys(props)) {
    if (isConditional(props[key])) {
      conditionals[key] = props[key] as SDUIConditional;
    } else {
      interpolatable[key] = props[key];
    }
  }

  return { interpolatable, conditionals };
}
```

#### Component Rendering with Fallback
```typescript
function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
) {
  if (!isVisible(component, context)) return null;

  const { interpolatable, conditionals } = separateConditionals(component.props);
  const interpolatedProps = {
    ...interpolateDeep(interpolatable, context),
    ...conditionals, // Passed as-is for adapter evaluation
  };

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={key}
        type={component.type}
        props={interpolatedProps}
      />
    );
  }

  return <Renderer key={key} props={interpolatedProps} context={context} />;
}
```

