const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
const DENIED_KEYS = new Set(['__proto__', 'constructor', 'prototype']);

export function resolveContextPath(
  context: SDUIContext,
  path: string,
): SDUIContextValue {
  const segments = path.trim().split('.');
  let current: SDUIContextValue = context;

  for (const segment of segments) {
    if (current === null || current === undefined) return '';
    if (typeof current !== 'object') return '';
    if (DENIED_KEYS.has(segment)) return ''; // Prototype pollution protection

    if (Array.isArray(current)) {
      const index = parseInt(segment, 10);
      if (isNaN(index) || index < 0 || index >= current.length) return '';
      current = current[index] as SDUIContextValue;
    } else {
      current = (current as SDUIContext)[segment];
    }
  }

  return current ?? '';
}

export function interpolateString(
  template: string,
  context: SDUIContext,
): string {
  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
    const value = resolveContextPath(context, path);
    if (value === null || value === undefined) return '';
    if (typeof value === 'object') return '';
    return String(value);
  });
}

export function interpolateDeep<T>(value: T, context: SDUIContext): T {
  if (typeof value === 'string') {
    return interpolateString(value, context) as T;
  }
  if (Array.isArray(value)) {
    return value.map(item => interpolateDeep(item, context)) as T;
  }
  if (value !== null && typeof value === 'object') {
    const result: Record<string, unknown> = {};
    for (const key of Object.keys(value)) {
      result[key] = interpolateDeep(
        (value as Record<string, unknown>)[key],
        context,
      );
    }
    return result as T;
  }
  return value;
}
```

**Security Features:**
- Prototype pollution protection via `DENIED_KEYS`
- Bounds checking for array indexing
- Type coercion guards

#### JSON Logic Evaluator
**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/utils/jsonLogic.ts`

```typescript
const MAX_DEPTH = 20; // Prevent infinite recursion
const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);

function evaluateComparison(
  operator: string,
  operands: [SDUILogicOperand, SDUILogicOperand],
  context: SDUIContext,
  depth: number,
): boolean {
  const left = resolveOperand(operands[0], context, depth);
  const right = resolveOperand(operands[1], context, depth);

  switch (operator) {
    case '==': return left == right;  // Loose equality
    case '!=': return left != right;
    case '>': 
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left > right;
    case '<': 
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left < right;
    case '>=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left >= right;
    case '<=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left <= right;
    default: return false;
  }
}

function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
  if (!rule || typeof rule !== 'object') return false;
  if (depth > MAX_DEPTH) return false;

  const keys = Object.keys(rule);
  if (keys.length === 0) return false;

  const operator = keys[0];
  const operands = (rule as Record<string, unknown>)[operator];

  // Logical operators: and, or, !
  if (operator === 'and') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === 'or') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === '!') {
    const inner = Array.isArray(operands) ? operands[0] : operands;
    return !evaluate(inner as SDUIRule, context, depth + 1);
  }

  // Comparison operators
  if (COMPARISON_OPS.has(operator)) {
    if (!Array.isArray(operands) || operands.length !== 2) return false;
    return evaluateComparison(
      operator,
      operands as [SDUILogicOperand, SDUILogicOperand],
      context,
      depth,
    );
  }

  return false;
}

export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
  return evaluate(rule, context, 0);
}
```

**Features:**
- Recursive evaluation with MAX_DEPTH guard
- Support for comparison (`==`, `!=`, `>`, `<`, `>=`, `<=`)
- Support for logical operators (`and`, `or`, `!`)
- Type-safe comparisons for numeric operators
- Loose equality for `==`/`!=`

#### Validation
**Location:** `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/sdui/utils/validation.ts`

```typescript
export function validateField(
  validation: SDUIValidation,
  context: SDUIContext,
): string | null {
  if (!validation?.rules || !Array.isArray(validation.rules)) return null;

  for (const entry of validation.rules) {
    if (!entry?.rule || !entry?.message) continue;
    const passes = evaluateRule(entry.rule, context);
    if (!passes) return entry.message;
  }

  return null;
}
```

Short-circuits on first validation failure.

