#### Example: ButtonAdapter (with conditional logic)
```typescript
interface ButtonProps extends SDUIComponentProps {
  text: string;
  disabled?: boolean;
  enabled?: SDUIConditional;
  mt?: string;
  mb?: string;
  icon?: string;
  isLoading?: boolean;
  testID?: string;
}

export default function ButtonAdapter({
  props,
  context,
}: {
  props: ButtonProps;
  context: SDUIContext;
}) {
  const { text, disabled, enabled, mt, mb, icon, isLoading, testID } = props;

  const isEnabled = enabled ? evaluateRule(enabled.rule, context) : true;
  const isDisabled = !!disabled || !isEnabled;

  return (
    <Button
      text={String(text)}
      onPress={() => {}}
      disabled={isDisabled}
      mt={mt}
      mb={mb}
      icon={icon}
      isLoading={!!isLoading}
      testID={testID}
    />
  );
}
```

#### Example: RichTextAdapter
```typescript
interface RichTextProps extends SDUIComponentProps {
  children: SDUIRichTextChild[];
  mt?: string;
  mb?: string;
  align?: string;
}

function renderNode(node: SDUIRichTextChild, index: number) {
  switch (node.type) {
    case 'text': {
      const style: Record<string, string> = {};
      if (node.bold) style.fontWeight = 'bold';
      if (node.italic) style.fontStyle = 'italic';
      return (
        <Text
          key={index}
          type="bodyMD"
          color={node.color}
          style={Object.keys(style).length > 0 ? style : undefined}
        >
          {node.value}
        </Text>
      );
    }
    case 'link':
      return (
        <Text
          key={index}
          type="bodyMD"
          color="PRYMARY_BASE_02"
          underline
          onPress={() => {}}
        >
          {node.text}
        </Text>
      );
    case 'icon':
      return (
        <Icon
          key={index}
          name={node.name}
          color={node.color}
          size={node.size ? String(node.size) : 'sm'}
        />
      );
    case 'br':
      return '\n';
    default:
      return null;
  }
}

export default function RichTextAdapter({
  props,
}: {
  props: RichTextProps;
  context: SDUIContext;
}) {
  const { children, mt, mb, align } = props;

  if (!Array.isArray(children) || children.length === 0) {
    return null;
  }

  return (
    <Text type="bodyMD" mt={mt} mb={mb} align={align}>
      {children.map(renderNode)}
    </Text>
  );
}
```

**Adapter Pattern Characteristics:**
- Stateless functional components
- Props type-extended from `SDUIComponentProps`
- Receive both `props` and `context` destructured
- Small focused components that map to design system components
- No event handlers implemented (onPress={() => {}})

